import{_ as e,o as t,c as r,ag as i}from"./chunks/framework.C9sp7nFj.js";const _=JSON.parse('{"title":"外滩与陆家嘴攻略2026 | iVoyageWiki","description":"上海外滩与陆家嘴旅游攻略，涵盖外滩万国建筑群、陆家嘴摩天大楼等必看景点","frontmatter":{"title":"外滩与陆家嘴攻略2026 | iVoyageWiki","description":"上海外滩与陆家嘴旅游攻略，涵盖外滩万国建筑群、陆家嘴摩天大楼等必看景点"},"headers":[],"relativePath":"destinations/中国/上海/外滩与陆家嘴.md","filePath":"destinations/中国/上海/外滩与陆家嘴.md","lastUpdated":null}'),o={name:"destinations/中国/上海/外滩与陆家嘴.md"};function n(l,a,h,d,s,c){return t(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="外滩与陆家嘴" tabindex="-1">外滩与陆家嘴 <a class="header-anchor" href="#外滩与陆家嘴" aria-label="Permalink to &quot;外滩与陆家嘴&quot;">​</a></h1><h2 id="城市概览" tabindex="-1">城市概览 <a class="header-anchor" href="#城市概览" aria-label="Permalink to &quot;城市概览&quot;">​</a></h2><p>外滩与陆家嘴隔黄浦江相望，是上海最经典的城市景观区。外滩拥有万国建筑博览群，陆家嘴则汇集了东方明珠、上海中心等摩天大楼。</p><h2 id="行前准备" tabindex="-1">行前准备 <a class="header-anchor" href="#行前准备" aria-label="Permalink to &quot;行前准备&quot;">​</a></h2><p>建议选择天气晴朗的日子前往，傍晚时分两岸灯光亮起景色最佳。穿舒适的鞋子，外滩步行道很长。</p><h2 id="交通指南" tabindex="-1">交通指南 <a class="header-anchor" href="#交通指南" aria-label="Permalink to &quot;交通指南&quot;">​</a></h2><p>地铁2号线、10号线南京东路站可到外滩，地铁2号线陆家嘴站直达陆家嘴。也可乘坐轮渡往返两岸。</p><h2 id="必去景点" tabindex="-1">必去景点 <a class="header-anchor" href="#必去景点" aria-label="Permalink to &quot;必去景点&quot;">​</a></h2><p>外滩观景平台、陆家嘴环形天桥、上海中心118层观光厅、东方明珠广播电视塔、外白渡桥。</p><h2 id="美食推荐" tabindex="-1">美食推荐 <a class="header-anchor" href="#美食推荐" aria-label="Permalink to &quot;美食推荐&quot;">​</a></h2><p>外滩沿线有多家高端餐厅，陆家嘴国金中心汇集各国美食。推荐尝试上海本帮菜和生煎包。</p><h2 id="购物指南" tabindex="-1">购物指南 <a class="header-anchor" href="#购物指南" aria-label="Permalink to &quot;购物指南&quot;">​</a></h2><p>南京东路步行街、陆家嘴正大广场、国金中心商场是主要购物区。</p><h2 id="行程规划" tabindex="-1">行程规划 <a class="header-anchor" href="#行程规划" aria-label="Permalink to &quot;行程规划&quot;">​</a></h2><p>建议下午游览外滩，傍晚乘轮渡到陆家嘴，登高看夜景。</p><h2 id="避坑指南" tabindex="-1">避坑指南 <a class="header-anchor" href="#避坑指南" aria-label="Permalink to &quot;避坑指南&quot;">​</a></h2><p>外滩沿线推销游船票和拍照的很多，注意比价。节假日人流量极大。</p>',17)])])}const u=e(o,[["render",n]]);export{_ as __pageData,u as default};
